import { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const ScoreBar = ({ score }) => {
  const color = score >= 70 ? '#10b981' : score >= 40 ? '#f59e0b' : '#ef4444';
  return (
    <div className="flex items-center gap-2">
      <div style={{ background: '#0a0d1a', width: 80, height: 5, borderRadius: 3 }}>
        <div style={{ background: color, width: `${score}%`, height: '100%', borderRadius: 3, boxShadow: `0 0 8px ${color}40` }} />
      </div>
      <span style={{ color }} className="text-xs font-bold">{score}</span>
    </div>
  );
};

export default function AdminDashboard() {
  const [projects, setProjects] = useState([]);
  const [stats, setStats] = useState(null);
  const [filter, setFilter] = useState('pending');
  const [loading, setLoading] = useState(true);
  const [actionNote, setActionNote] = useState('');
  const [actionTarget, setActionTarget] = useState(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const [deletingId, setDeletingId] = useState(null);

  useEffect(() => {
    fetchStats();
    fetchProjects();
  }, [filter]);

  const fetchStats = () => {
    axios.get('/api/admin/stats').then(r => setStats(r.data)).catch(console.error);
  };

  const fetchProjects = () => {
    setLoading(true);
    axios.get(`/api/admin/projects?status=${filter}`)
      .then(r => setProjects(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const handleDecision = async (id, decision) => {
    try {
      await axios.patch(`/api/admin/projects/${id}/${decision}`, { adminNote: actionNote });
      toast.success(`Project ${decision}d successfully`);
      setActionTarget(null);
      setActionNote('');
      fetchProjects();
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Action failed');
    }
  };

  const handleDelete = async (id) => {
    setDeletingId(id);
    try {
      await axios.delete(`/api/admin/projects/${id}`);
      setProjects(prev => prev.filter(p => p._id !== id));
      setConfirmDeleteId(null);
      toast.success('Project deleted successfully.');
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete project.');
    } finally {
      setDeletingId(null);
    }
  };

  const statsList = stats ? [
    { label: 'Total Projects', value: stats.totalProjects, color: '#00d4aa' },
    { label: 'Pending Review', value: stats.pendingProjects, color: '#f59e0b' },
    { label: 'Approved', value: stats.approvedProjects, color: '#10b981' },
    { label: 'Rejected', value: stats.rejectedProjects, color: '#ef4444' },
    { label: 'Total Users', value: stats.totalUsers, color: '#8b5cf6' },
    { label: 'Total Funded', value: `$${(stats.totalFunding || 0).toLocaleString()}`, color: '#00d4aa' },
  ] : [];

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0a0d1a 0%, #0f1219 25%, #0d1422 50%, #0a0f1a 75%, #0a0d1a 100%)',
      backgroundAttachment: 'fixed',
      position: 'relative',
      overflow: 'hidden'
    }} className="px-6 py-10">
      {/* Sophisticated Background Effects */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        pointerEvents: 'none',
        zIndex: 0,
        background: 'radial-gradient(circle at 20% 50%, rgba(0, 212, 170, 0.08) 0%, transparent 50%), radial-gradient(circle at 80% 80%, rgba(139, 92, 246, 0.06) 0%, transparent 50%)',
      }} />

      {/* Grain Texture Overlay */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        pointerEvents: 'none',
        zIndex: 1,
        backgroundImage: 'url("data:image/svg+xml,%3Csvg viewBox="0 0 400 400" xmlns="http://www.w3.org/2000/svg"%3E%3Cfilter id="noiseFilter"%3E%3CfeTurbulence type="fractalNoise" baseFrequency="0.9" numOctaves="4" result="noise" seed="2" /%3E%3CfeColorMatrix in="noise" type="saturate" values="0" /%3E%3C/filter%3E%3Crect width="400" height="400" filter="url(%23noiseFilter)" opacity="0.03" /%3E%3C/svg%3E")',
        backgroundSize: '200px 200px',
        opacity: 0.4,
      }} />

      <div className="max-w-6xl mx-auto relative z-10">
        {/* Header Section */}
        <div className="mb-10 relative z-20">
          <div className="flex items-center gap-2 mb-2">
            <span style={{ color: '#00d4aa', fontSize: '18px', filter: 'drop-shadow(0 0 4px rgba(0, 212, 170, 0.4))' }}>⚙</span>
            <span className="text-gray-400 text-sm uppercase tracking-widest">Admin Panel</span>
          </div>
          <h1 style={{ 
            fontFamily: 'Syne, sans-serif',
            background: 'linear-gradient(135deg, #ffffff 0%, #00d4aa 100%)',
            backgroundClip: 'text',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            fontSize: '2.5rem'
          }} className="font-black">BackerSphere X</h1>
        </div>

        {/* Stats Grid */}
        {stats && (
          <div className="grid grid-cols-6 gap-4 mb-10">
            {statsList.map((s, idx) => (
              <div 
                key={s.label}
                style={{
                  background: 'linear-gradient(135deg, rgba(17, 24, 39, 0.8) 0%, rgba(15, 23, 42, 0.6) 100%)',
                  border: '1px solid rgba(0, 212, 170, 0.1)',
                  backdropFilter: 'blur(10px)',
                  transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                  cursor: 'pointer',
                  animation: `slideUp 0.5s ease-out ${idx * 0.05}s both`,
                }}
                className="p-5 rounded-2xl text-center hover:border-teal-500/30 hover:bg-opacity-100 group"
                onMouseEnter={(e) => {
                  e.currentTarget.style.boxShadow = `0 20px 40px rgba(0, 212, 170, 0.15), inset 0 0 40px rgba(0, 212, 170, 0.05)`;
                  e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.3)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.boxShadow = 'none';
                  e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.1)';
                }}
              >
                <div style={{ color: s.color, fontFamily: 'Syne, sans-serif', textShadow: `0 0 20px ${s.color}40` }} className="text-3xl font-black">{s.value}</div>
                <div className="text-gray-500 text-xs mt-2 uppercase tracking-wide">{s.label}</div>
              </div>
            ))}
          </div>
        )}

        <style>{`
          @keyframes slideUp {
            from {
              opacity: 0;
              transform: translateY(20px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }

          @keyframes fadeIn {
            from {
              opacity: 0;
            }
            to {
              opacity: 1;
            }
          }
        `}</style>

        {/* Filter Tabs */}
        <div className="flex gap-3 mb-8 flex-wrap">
          {['pending', 'approved', 'rejected', 'all'].map(f => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              style={{
                background: filter === f 
                  ? 'linear-gradient(135deg, #00d4aa 0%, #00b8a6 100%)' 
                  : 'rgba(17, 24, 39, 0.6)',
                color: filter === f ? '#0a0d1a' : '#9ca3af',
                border: filter === f ? 'none' : '1px solid rgba(31, 41, 55, 0.8)',
                boxShadow: filter === f ? '0 10px 30px rgba(0, 212, 170, 0.2)' : 'none',
                backdropFilter: 'blur(10px)',
                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
              }}
              className="px-6 py-2.5 rounded-xl text-sm font-semibold capitalize hover:border-teal-500/50"
            >
              {f}
            </button>
          ))}
        </div>

        {/* Projects List */}
        {loading ? (
          <div className="text-center text-gray-500 py-20 text-base">Loading projects...</div>
        ) : projects.length === 0 ? (
          <div className="text-center text-gray-500 py-20 text-base">No {filter} projects found</div>
        ) : (
          <div className="space-y-4">
            {projects.map((p, idx) => (
              <div
                key={p._id}
                style={{
                  background: 'linear-gradient(135deg, rgba(17, 24, 39, 0.9) 0%, rgba(15, 23, 42, 0.7) 100%)',
                  border: '1px solid rgba(31, 41, 55, 0.6)',
                  backdropFilter: 'blur(10px)',
                  transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                  animation: `fadeIn 0.5s ease-out ${idx * 0.05}s both`,
                }}
                className="rounded-2xl p-7 hover:border-teal-500/30 hover:shadow-2xl group"
                onMouseEnter={(e) => {
                  e.currentTarget.style.boxShadow = '0 30px 60px rgba(0, 212, 170, 0.1), inset 0 0 40px rgba(0, 212, 170, 0.05)';
                  e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.25)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.boxShadow = 'none';
                  e.currentTarget.style.borderColor = 'rgba(31, 41, 55, 0.6)';
                }}
              >

                <div className="flex items-start justify-between mb-5">
                  <div className="flex-1">
                    <h3 className="font-bold text-lg mb-2 text-white">{p.title}</h3>
                    <div className="flex gap-3 text-xs text-gray-400">
                      <span>By {p.innovator?.name}</span>
                      <span>·</span>
                      <span>{p.category}</span>
                      <span>·</span>
                      <span>Goal: ${p.fundingGoal?.toLocaleString()}</span>
                      <span>·</span>
                      <span>Team: {p.teamSize}</span>
                    </div>
                  </div>

                  <div className="flex items-center gap-3 ml-4">
                    <span style={{
                      color: p.status === 'approved' ? '#10b981' : p.status === 'rejected' ? '#ef4444' : '#f59e0b',
                      background: p.status === 'approved' ? 'rgba(16, 185, 129, 0.15)' : p.status === 'rejected' ? 'rgba(239, 68, 68, 0.15)' : 'rgba(245, 158, 11, 0.15)',
                      border: `1px solid ${p.status === 'approved' ? 'rgba(16, 185, 129, 0.4)' : p.status === 'rejected' ? 'rgba(239, 68, 68, 0.4)' : 'rgba(245, 158, 11, 0.4)'}`,
                      boxShadow: `0 0 15px ${p.status === 'approved' ? '#10b98130' : p.status === 'rejected' ? '#ef444430' : '#f59e0b30'}`,
                      backdropFilter: 'blur(8px)',
                    }} className="px-3 py-1 rounded-full text-xs font-semibold capitalize">
                      {p.status}
                    </span>

                    {/* Delete Button */}
                    {confirmDeleteId === p._id ? (
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-gray-400">Sure?</span>
                        <button
                          onClick={() => handleDelete(p._id)}
                          disabled={deletingId === p._id}
                          style={{
                            background: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)',
                            color: 'white',
                            boxShadow: '0 8px 20px rgba(239, 68, 68, 0.3)',
                          }}
                          className="px-3 py-1 rounded-lg text-xs font-semibold hover:opacity-90 disabled:opacity-60 transition-all"
                        >
                          {deletingId === p._id ? 'Deleting...' : 'Yes'}
                        </button>
                        <button
                          onClick={() => setConfirmDeleteId(null)}
                          style={{ background: 'rgba(31, 41, 55, 0.8)', color: '#9ca3af' }}
                          className="px-3 py-1 rounded-lg text-xs font-semibold transition-all hover:bg-opacity-100"
                        >
                          No
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => setConfirmDeleteId(p._id)}
                        style={{
                          border: '1px solid rgba(239, 68, 68, 0.3)',
                          color: '#ef4444',
                          transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                        }}
                        className="px-3 py-1 rounded-lg text-xs font-semibold hover:border-red-500 hover:bg-red-500 hover:bg-opacity-20 transition-all"
                      >
                        🗑 Delete
                      </button>
                    )}
                  </div>
                </div>

                <p className="text-gray-400 text-sm mb-5 leading-relaxed line-clamp-2">{p.description}</p>

                {/* AI Scores */}
                {p.aiEvaluation?.feasibilityScore !== null ? (
                  <div style={{
                    background: 'linear-gradient(135deg, rgba(10, 13, 26, 0.9) 0%, rgba(10, 15, 30, 0.8) 100%)',
                    border: '1px solid rgba(0, 212, 170, 0.25)',
                    boxShadow: '0 0 30px rgba(0, 212, 170, 0.1), inset 0 0 30px rgba(0, 212, 170, 0.03)',
                    backdropFilter: 'blur(10px)',
                  }} className="rounded-2xl p-5 mb-5">
                    <p style={{ color: '#00d4aa', textShadow: '0 0 10px rgba(0, 212, 170, 0.3)' }} className="text-xs font-black uppercase tracking-widest mb-4">
                      ✦ Gemini AI Evaluation
                    </p>
                    <div className="grid grid-cols-2 gap-4 mb-4">
                      <div>
                        <div className="text-gray-500 text-xs mb-2 uppercase tracking-wide">Feasibility Score</div>
                        <ScoreBar score={p.aiEvaluation.feasibilityScore} />
                      </div>
                      <div>
                        <div className="text-gray-500 text-xs mb-2 uppercase tracking-wide">Success Probability</div>
                        <ScoreBar score={p.aiEvaluation.successProbability} />
                      </div>
                    </div>
                    <p className="text-gray-400 text-xs leading-relaxed">{p.aiEvaluation.explanation}</p>
                  </div>
                ) : (
                  <div className="text-gray-500 text-sm mb-5">⏳ AI evaluation pending...</div>
                )}

                {/* Approve / Reject Actions */}
                {p.status === 'pending' && (
                  <div>
                    {actionTarget === p._id ? (
                      <div className="flex gap-3 items-center">
                        <input
                          value={actionNote}
                          onChange={e => setActionNote(e.target.value)}
                          style={{
                            background: 'rgba(10, 13, 26, 0.9)',
                            border: '1px solid rgba(0, 212, 170, 0.2)',
                            color: 'white',
                            backdropFilter: 'blur(10px)',
                          }}
                          className="flex-1 px-4 py-2.5 rounded-lg text-sm focus:outline-none focus:border-teal-500/50 transition-all"
                          placeholder="Admin note (optional)..."
                        />
                        <button
                          onClick={() => handleDecision(p._id, 'approve')}
                          style={{
                            background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)',
                            color: 'white',
                            boxShadow: '0 8px 20px rgba(16, 185, 129, 0.3)',
                          }}
                          className="px-5 py-2.5 rounded-lg text-sm font-semibold hover:shadow-lg transition-all"
                        >
                          ✓ Approve
                        </button>
                        <button
                          onClick={() => handleDecision(p._id, 'reject')}
                          style={{
                            background: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)',
                            color: 'white',
                            boxShadow: '0 8px 20px rgba(239, 68, 68, 0.3)',
                          }}
                          className="px-5 py-2.5 rounded-lg text-sm font-semibold hover:shadow-lg transition-all"
                        >
                          ✗ Reject
                        </button>
                        <button
                          onClick={() => { setActionTarget(null); setActionNote(''); }}
                          className="text-gray-400 text-sm hover:text-gray-300 transition-all"
                        >
                          Cancel
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => setActionTarget(p._id)}
                        style={{
                          border: '1px solid rgba(0, 212, 170, 0.25)',
                          color: '#9ca3af',
                          background: 'rgba(0, 212, 170, 0.05)',
                          backdropFilter: 'blur(10px)',
                          transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                        }}
                        className="px-5 py-2.5 rounded-lg text-sm font-semibold hover:border-teal-500 hover:text-white hover:bg-teal-500/10 transition-all"
                      >
                        Review & Decide
                      </button>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
